// Probe 11 curated critical webhook endpoints with junk Bearer.
// Healthy responses are 401 (auth gate rejecting) or 400 (input gate).
// 200 is acceptable too — means workflow ran and returned empty for
// the junk Bearer (cosmetic only). 404 is the failure we care about:
// it means the webhook is not registered in n8n's runtime map.
//
// Uses this.helpers.httpRequest to issue probes from inside the
// workflow execution context. Times each probe at 8s max.
const PUBLIC_BASE = $env.CLX_WEBHOOK_BASE || 'https://automation.crystallux.org/webhook';

const ENDPOINTS = [
  'admin/list-leads',
  'admin/comms-log',
  'admin/system-health',
  'admin/workflow-status',
  'admin/sales-engine/activity',
  'admin/chat',
  'admin/market-intelligence/summary',
  'admin/sentinel/comms/summary',
  'admin/ciro/alerts',
  'public/quote/fetch',
  'public/mga/apply'
];

async function probe(path) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: PUBLIC_BASE + '/' + path,
      headers: {
        'Authorization': 'Bearer junk',
        'Content-Type': 'application/json'
      },
      body: '{}',
      timeout: 8000,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    const code = r.statusCode || r.status || 0;
    return { path: path, code: code, ok: code !== 404 };
  } catch (e) {
    // Network error or timeout — treat as unhealthy but distinguish from 404
    return { path: path, code: 0, ok: false, error: (e.message || String(e)).slice(0, 200) };
  }
}

const boundProbe = probe.bind(this);
const results = [];
for (const p of ENDPOINTS) {
  results.push(await boundProbe(p));
}

const unhealthy = results.filter(function (r) { return !r.ok; });
const notFound  = results.filter(function (r) { return r.code === 404; });
const errors    = results.filter(function (r) { return r.code === 0; });
const healthy   = results.filter(function (r) { return r.ok; });

const severity = notFound.length >= 3 ? 'critical' : (notFound.length > 0 ? 'warning' : 'info');
const should_email = severity === 'critical';

return { json: {
  timestamp: new Date().toISOString(),
  total_probed: results.length,
  healthy_count:    healthy.length,
  unhealthy_count:  unhealthy.length,
  not_found_count:  notFound.length,
  network_error_count: errors.length,
  severity: severity,
  should_alert: unhealthy.length > 0,
  should_email: should_email,
  results: results,
  unhealthy_list: unhealthy
} };

const r = $input.item.json;
const paths = (r.unhealthy_list || []).map(function (u) { return u.path + ' (' + u.code + ')'; }).join(', ');

return { json: {
  sentinel_alert_row: {
    module_name: 'health_monitoring',
    alert_type: 'webhook_health_probe',
    severity: r.severity,
    title: r.not_found_count >= 3
      ? 'Webhook routing degraded — ' + r.not_found_count + ' endpoints returning 404'
      : (r.not_found_count > 0
          ? r.not_found_count + ' webhook(s) not registered'
          : r.unhealthy_count + ' webhook(s) unhealthy'),
    message: 'Probed ' + r.total_probed + ' endpoints. ' + r.healthy_count + ' healthy, ' + r.not_found_count + ' returning 404, ' + r.network_error_count + ' network errors. Affected: ' + paths,
    details: { results: r.results, unhealthy_list: r.unhealthy_list },
    status: 'open',
    aggregation_key: 'webhook_health_probe'
  },
  meta: {
    should_email: r.should_email,
    not_found_count: r.not_found_count,
    paths_short: paths
  }
} };

const ctx = $('Probe Endpoints').first().json;
const maryEmail = $env.MARY_EMAIL || 'adesholaakintunde@gmail.com';
const fromAddr  = $env.POSTMARK_FROM || 'mary@crystallux.org';

const affected = (ctx.unhealthy_list || []).map(function (u) {
  return '<li style="margin:4px 0;font-family:ui-monospace,Menlo,monospace;font-size:12px;">' +
    '<code>' + u.path + '</code> ' +
    '<span style="color:' + (u.code === 404 ? '#dc2626' : '#b45309') + ';font-weight:700;">HTTP ' + u.code + '</span>' +
    (u.error ? '<br><span style="color:#94a3b8;font-size:11px;">' + u.error + '</span>' : '') +
  '</li>';
}).join('');

const htmlBody = '<div style="font-family:Arial,Helvetica,sans-serif;color:#0f172a;max-width:620px;">' +
  '<div style="padding:20px 24px;background:linear-gradient(135deg,#dc2626 0%,#991b1b 100%);color:#fff;border-radius:8px 8px 0 0;">' +
    '<div style="font-size:12px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;opacity:0.85;">Crystallux Sentinel</div>' +
    '<div style="font-size:22px;font-weight:800;margin-top:6px;">Webhook routing degraded</div>' +
  '</div>' +
  '<div style="padding:24px;background:#fff;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">' +
    '<p style="margin:0 0 12px;font-size:15px;line-height:1.6;">' +
      '<strong>' + ctx.not_found_count + ' of ' + ctx.total_probed + '</strong> critical webhook endpoints returned 404 in the last probe. This means n8n\'s webhook map needs a refresh.' +
    '</p>' +
    '<p style="margin:0 0 8px;font-size:13px;color:#64748b;">Affected endpoints:</p>' +
    '<ul style="margin:0 0 16px;padding:0;list-style:none;background:#f8fafc;padding:12px 16px;border-radius:6px;">' + affected + '</ul>' +
    '<p style="margin:0 0 12px;font-size:14px;line-height:1.6;"><strong>Recommended action:</strong></p>' +
    '<pre style="background:#0f172a;color:#fff;padding:14px;border-radius:6px;font-size:12px;line-height:1.5;margin:0;">docker restart n8n</pre>' +
    '<p style="margin:12px 0 0;font-size:13px;color:#64748b;">Wait 30s after restart, then the next probe (within 30 min) should show recovery. If it still fails, run <code>bash scripts/n8n/nuke-and-reimport.sh</code> on the VPS as the recovery escalation.</p>' +
    '<p style="margin:20px 0 0;font-size:11px;color:#94a3b8;">Probed at ' + ctx.timestamp + ' &middot; <a href="https://admin.crystallux.org/pages/sentinel.html" style="color:#dc2626;">Open Sentinel dashboard</a></p>' +
  '</div>' +
  '</div>';

return { json: {
  postmark_payload: {
    From: fromAddr,
    To: maryEmail,
    Subject: '[CRITICAL] ' + ctx.not_found_count + ' webhook(s) returning 404 - n8n needs restart',
    HtmlBody: htmlBody,
    TextBody: ctx.not_found_count + ' webhook(s) returning 404. Run docker restart n8n. Affected: ' + (ctx.unhealthy_list || []).map(function (u) { return u.path; }).join(', '),
    MessageStream: 'outbound'
  }
} };
